static unsigned long long reduce_verification(SimulationData GSD, int n)
{
	thrust::device_ptr<unsigned long> vptr(GSD.verification);
	unsigned long sum = thrust::reduce(vptr, vptr + n, (unsigned long)0, thrust::plus<unsigned long>());
	return (unsigned long long)sum;
}

unsigned long long run_event_based_simulation_baseline(Inputs in, SimulationData GSD, int mype)
{
	if (mype == 0)
		printf("Beginning event based simulation...\n");

	int threads = 256;
	int blocks = (in.lookups + threads - 1) / threads;
	xs_lookup_kernel_baseline<<<blocks, threads>>>(in, GSD);
	gpuErrchk(cudaPeekAtLastError());
	gpuErrchk(cudaDeviceSynchronize());

	return reduce_verification(GSD, in.lookups);
}

unsigned long long run_event_based_simulation_optimization_1(Inputs in, SimulationData GSD, int mype)
{
	char *optimization_name = (char*)"Optimization 1 - Kernel splitting + full material & energy sort";
	if (mype == 0) printf("Simulation Kernel:\"%s\"\n", optimization_name);

	if (GSD.p_energy_samples == nullptr || GSD.length_p_energy_samples < in.lookups)
	{
		if (GSD.p_energy_samples) gpuErrchk(cudaFree(GSD.p_energy_samples));
		if (GSD.mat_samples) gpuErrchk(cudaFree(GSD.mat_samples));
		gpuErrchk(cudaMalloc((void**)&GSD.p_energy_samples, (size_t)in.lookups * sizeof(double)));
		gpuErrchk(cudaMalloc((void**)&GSD.mat_samples, (size_t)in.lookups * sizeof(int)));
		GSD.length_p_energy_samples = in.lookups;
		GSD.length_mat_samples = in.lookups;
		if (mype == 0)
			printf("Allocated an additional %.0lf MB of data on GPU.\n",
			       ((double)in.lookups * (sizeof(double) + sizeof(int))) / 1024.0 / 1024.0);
	}

	int threads = 256;
	int blocks = (in.lookups + threads - 1) / threads;

	sampling_kernel<<<blocks, threads>>>(in, GSD);
	gpuErrchk(cudaPeekAtLastError());
	gpuErrchk(cudaDeviceSynchronize());
	if (mype == 0) printf("finished sampling...\n");

	double start = get_time();

	thrust::device_ptr<int> mptr(GSD.mat_samples);
	thrust::device_ptr<double> eptr(GSD.p_energy_samples);
	thrust::sort_by_key(mptr, mptr + in.lookups, eptr);

	double stop = get_time();
	if (mype == 0) printf("Material sort took %.3lf seconds\n", stop - start);

	start = stop;
	std::vector<int> num_samples_per_mat(12, 0), offsets(12, 0);
	for (int m = 0; m < 12; m++)
		num_samples_per_mat[m] = (int)thrust::count(mptr, mptr + in.lookups, m);
	for (int m = 1; m < 12; m++)
		offsets[m] = offsets[m - 1] + num_samples_per_mat[m - 1];
	stop = get_time();
	if (mype == 0) printf("Counting samples and offsets took %.3lf seconds\n", stop - start);

	start = stop;
	for (int m = 0; m < 12; m++)
	{
		int off = offsets[m];
		int cnt = num_samples_per_mat[m];
		if (cnt > 1)
			thrust::sort_by_key(eptr + off, eptr + off + cnt, mptr + off);
	}
	stop = get_time();
	if (mype == 0) printf("Energy Sorts took %.3lf seconds\n", stop - start);

	start = get_time();
	xs_lookup_kernel_optimization_1<<<blocks, threads>>>(in, GSD);
	gpuErrchk(cudaPeekAtLastError());
	gpuErrchk(cudaDeviceSynchronize());
	stop = get_time();
	if (mype == 0) printf("XS Lookups took %.3lf seconds\n", stop - start);

	return reduce_verification(GSD, in.lookups);
}

